# src/api/users.py — untyped
from fastapi import APIRouter

router = APIRouter()

@router.post("/users")
def create_user(payload):
    if "email" not in payload:
        return {"error": "email required"}
    user = save_user(payload)
    return {"id": user.id, "email": user.email}

def save_user(data):
    return User.objects.create(**data)

# src/api/users.py — typed
from typing import TypedDict
from fastapi import APIRouter, HTTPException
from pydantic import BaseModel, EmailStr

from src.models import User

router = APIRouter()


class CreateUserPayload(BaseModel):
    email: EmailStr
    name: str
    age: int | None = None


class CreateUserResponse(TypedDict):
    id: int
    email: str


@router.post("/users", response_model=CreateUserResponse)
def create_user(payload: CreateUserPayload) -> CreateUserResponse:
    user = save_user(payload)
    return {"id": user.id, "email": user.email}


def save_user(data: CreateUserPayload) -> User:
    return User.objects.create(**data.model_dump())
